@startuml
skinparam ClassDiagram labelStyle fontname "Helvetica"
skinparam Actor labelStyle fontname "Helvetica"
skinparam Interface labelStyle fontname "Helvetica"
skinparam Class labelStyle fontname "Helvetica"

class Menu {
    label "C" as icon
    method main(String)
}

class Personnage {
    label "A" as icon
    method combattre()
    method setArme(ComportementArme)
}

class ComportementArme {
    label "I" as icon
    method utiliserArme()
}

class Chevalier {
    label "C" as icon
}

class Reine {
    label "C" as icon
}

class Roi {
    label "C" as icon
}

class Troll {
    label "C" as icon
}

class ComportementArc {
    label "C" as icon
    method utiliserArme()
}

class ComportementEpee {
    label "C" as icon
    method utiliserArme()
}

class ComportementPoignard {
    label "C" as icon
    method utiliserArme()
}

Personnage <|-- Chevalier
Personnage <|-- Reine
Personnage <|-- Roi
Personnage <|-- Troll

Personnage ..> ComportementArme : 1

ComportementArme ..> ComportementArc
ComportementArme ..> ComportementEpee
ComportementArme ..> ComportementPoignard

@enduml
